export interface CalendarEvent {
  id: string;
  title: string;
  description?: string;
  start: string; // ISO 8601 date string
  end: string;   // ISO 8601 date string
  color: EventColor;
  isAllDay: boolean;
  location?: string;
}

export enum EventColor {
  BLUE = 'blue',
  RED = 'red',
  GREEN = 'green',
  YELLOW = 'yellow',
  PURPLE = 'purple',
  INDIGO = 'indigo',
  PINK = 'pink',
  GRAY = 'gray'
}

export interface DayData {
  date: Date;
  isCurrentMonth: boolean;
  isToday: boolean;
  events: CalendarEvent[];
}

export interface SmartEventResponse {
  title: string;
  start: string;
  end: string;
  description?: string;
  location?: string;
  isAllDay?: boolean;
}

export const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export const WEEK_DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

export const getDaysInMonth = (year: number, month: number): number => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfMonth = (year: number, month: number): number => {
  return new Date(year, month, 1).getDay();
};

export const isSameDay = (d1: Date, d2: Date): boolean => {
  return (
    d1.getFullYear() === d2.getFullYear() &&
    d1.getMonth() === d2.getMonth() &&
    d1.getDate() === d2.getDate()
  );
};

export const formatDateForInput = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const formatTime = (isoString: string): string => {
  const date = new Date(isoString);
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

export const generateCalendarGrid = (currentDate: Date): { date: Date; isCurrentMonth: boolean }[] => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  // Previous month days to fill grid
  const daysInPrevMonth = getDaysInMonth(year, month - 1);
  const prevMonthDays = Array.from({ length: firstDay }, (_, i) => {
    return {
      date: new Date(year, month - 1, daysInPrevMonth - firstDay + i + 1),
      isCurrentMonth: false
    };
  });

  // Current month days
  const currentMonthDays = Array.from({ length: daysInMonth }, (_, i) => {
    return {
      date: new Date(year, month, i + 1),
      isCurrentMonth: true
    };
  });

  // Next month days to fill remaining grid (42 cells total for 6 rows)
  const remainingCells = 42 - (prevMonthDays.length + currentMonthDays.length);
  const nextMonthDays = Array.from({ length: remainingCells }, (_, i) => {
    return {
      date: new Date(year, month + 1, i + 1),
      isCurrentMonth: false
    };
  });

  return [...prevMonthDays, ...currentMonthDays, ...nextMonthDays];
};

export const getColorClasses = (color: string) => {
    switch (color) {
        case 'blue': return 'bg-blue-100 text-blue-700 border-blue-200 hover:bg-blue-200';
        case 'red': return 'bg-red-100 text-red-700 border-red-200 hover:bg-red-200';
        case 'green': return 'bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-200';
        case 'yellow': return 'bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-200';
        case 'purple': return 'bg-purple-100 text-purple-700 border-purple-200 hover:bg-purple-200';
        case 'indigo': return 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200';
        case 'pink': return 'bg-pink-100 text-pink-700 border-pink-200 hover:bg-pink-200';
        default: return 'bg-gray-100 text-gray-700 border-gray-200 hover:bg-gray-200';
    }
};

import { GoogleGenAI, Type } from "@google/genai";
import { SmartEventResponse } from "../types";

const parseEventWithGemini = async (text: string): Promise<SmartEventResponse | null> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.error("API Key not found");
    return null;
  }

  const ai = new GoogleGenAI({ apiKey });
  const now = new Date();
  const nowIso = now.toISOString();

  const prompt = `
    Current Date/Time: ${nowIso} (User's local time zone context).
    User Input: "${text}"

    Task: Extract calendar event details from the user input.
    Rules:
    1. 'start' and 'end' must be valid ISO 8601 strings (e.g., YYYY-MM-DDTHH:mm:00).
    2. If duration is not specified, assume 1 hour from start time.
    3. If time is not specified but date is, set isAllDay to true, and use 00:00 for start and 23:59 for end on that date.
    4. Infer relative dates (e.g., "tomorrow", "next Friday") based on Current Date.
    5. Return JSON only.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            start: { type: Type.STRING },
            end: { type: Type.STRING },
            description: { type: Type.STRING },
            location: { type: Type.STRING },
            isAllDay: { type: Type.BOOLEAN },
          },
          required: ["title", "start", "end"],
        },
      },
    });

    if (response.text) {
        return JSON.parse(response.text) as SmartEventResponse;
    }
    return null;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

export { parseEventWithGemini };

import React, { useEffect } from 'react';
import { X } from 'lucide-react';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
}

export const Modal: React.FC<ModalProps> = ({ isOpen, onClose, title, children }) => {
  useEffect(() => {
    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    if (isOpen) window.addEventListener('keydown', handleEscape);
    return () => window.removeEventListener('keydown', handleEscape);
  }, [isOpen, onClose]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-md overflow-hidden animate-in fade-in zoom-in-95 duration-200">
        <div className="flex justify-between items-center p-4 border-b border-gray-100">
          <h3 className="text-lg font-semibold text-gray-800">{title}</h3>
          <button 
            onClick={onClose}
            className="p-1 rounded-full hover:bg-gray-100 text-gray-500 transition-colors"
          >
            <X size={20} />
          </button>
        </div>
        <div className="p-4">
          {children}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor, SmartEventResponse } from '../types';
import { parseEventWithGemini } from '../services/geminiService';
import { Sparkles, Loader2, CalendarPlus } from 'lucide-react';

interface SmartAddModalProps {
  isOpen: boolean;
  onClose: () => void;
  onAddEvent: (event: Omit<CalendarEvent, 'id'>) => void;
}

export const SmartAddModal: React.FC<SmartAddModalProps> = ({ isOpen, onClose, onAddEvent }) => {
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    setIsLoading(true);
    setError(null);

    try {
      const result: SmartEventResponse | null = await parseEventWithGemini(input);

      if (result) {
        onAddEvent({
          title: result.title,
          start: result.start,
          end: result.end,
          description: result.description || '',
          location: result.location || '',
          isAllDay: result.isAllDay || false,
          color: EventColor.INDIGO, // Default color for AI events
        });
        setInput('');
        onClose();
      } else {
        setError("Could not understand the event details. Please try again.");
      }
    } catch (err) {
      setError("Failed to connect to the intelligence service. Please check your connection.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Ask AI to Plan">
      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="relative">
            <textarea
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="e.g., 'Lunch with Sarah tomorrow at 12:30 PM for 1 hour at The Diner'"
            className="w-full h-32 p-4 text-gray-700 border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none resize-none bg-gray-50"
            autoFocus
            />
            <div className="absolute top-3 right-3 text-indigo-400 opacity-50">
                <Sparkles size={20} />
            </div>
        </div>

        {error && (
            <div className="text-sm text-red-500 bg-red-50 p-3 rounded-lg border border-red-100">
                {error}
            </div>
        )}

        <div className="flex justify-end gap-3">
            <button
                type="button"
                onClick={onClose}
                className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
            >
                Cancel
            </button>
            <button
                type="submit"
                disabled={isLoading || !input.trim()}
                className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-indigo-600 rounded-lg hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all shadow-sm hover:shadow-md"
            >
                {isLoading ? <Loader2 className="animate-spin" size={16} /> : <Sparkles size={16} />}
                {isLoading ? 'Processing...' : 'Create Magic Event'}
            </button>
        </div>

        <div className="text-xs text-center text-gray-400 mt-2">
            Powered by Gemini 3 Flash. Natural Language Understanding.
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor } from '../types';
import { formatDateForInput } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon } from 'lucide-react';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date;
  existingEvent?: CalendarEvent | null;
}

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [start, setStart] = useState('');
  const [end, setEnd] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [color, setColor] = useState<EventColor>(EventColor.BLUE);
  const [isAllDay, setIsAllDay] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        setStart(existingEvent.start);
        setEnd(existingEvent.end);
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setColor(existingEvent.color);
        setIsAllDay(existingEvent.isAllDay);
      } else {
        const d = initialDate || new Date();
        const startDate = new Date(d);
        startDate.setHours(9, 0, 0, 0); // Default to 9 AM
        const endDate = new Date(startDate);
        endDate.setHours(10, 0, 0, 0); // Default 1 hour duration

        setTitle('');
        setStart(formatDateForInput(startDate));
        setEnd(formatDateForInput(endDate));
        setDescription('');
        setLocation('');
        setColor(EventColor.BLUE);
        setIsAllDay(false);
      }
    }
  }, [isOpen, existingEvent, initialDate]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start,
      end,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4">

        {/* Title */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        {/* Date & Time */}
        <div className="grid grid-cols-1 gap-3">
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                 <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                        <Clock size={16} />
                    </div>
                    <input
                        type="datetime-local"
                        required
                        value={start}
                        onChange={(e) => setStart(e.target.value)}
                        className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                 </div>
            </div>
            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                        <Clock size={16} />
                    </div>
                    <input
                        type="datetime-local"
                        required
                        value={end}
                        onChange={(e) => setEnd(e.target.value)}
                        className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                    />
                </div>
            </div>
        </div>

        {/* All Day Toggle */}
        <div className="flex items-center gap-2">
            <input 
                type="checkbox" 
                id="isAllDay"
                checked={isAllDay}
                onChange={(e) => setIsAllDay(e.target.checked)}
                className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500"
            />
            <label htmlFor="isAllDay" className="text-sm text-gray-700">All day event</label>
        </div>

        {/* Location */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        {/* Description */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        {/* Color Picker */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Color</label>
            <div className="flex gap-2 flex-wrap">
                {Object.values(EventColor).map((c) => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setColor(c)}
                        className={`w-6 h-6 rounded-full transition-transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-gray-300 ${color === c ? 'ring-2 ring-offset-1 ring-gray-400 scale-110' : ''}`}
                        style={{ backgroundColor: c === 'white' ? '#eee' : `var(--color-${c}-400, ${c})` }}
                    />
                ))}
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div></div>}

            <div className="flex gap-2">
                <button
                    type="button"
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                >
                    Cancel
                </button>
                <button
                    type="submit"
                    className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                >
                    Save
                </button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Plus, Sparkles, Calendar as CalendarLogo } from 'lucide-react';
import { CalendarEvent, EventColor, DayData } from './types';
import { 
    generateCalendarGrid, 
    MONTH_NAMES, 
    WEEK_DAYS, 
    isSameDay, 
    formatTime,
    getColorClasses 
} from './utils/dateUtils';
import { EventModal } from './components/EventModal';
import { SmartAddModal } from './components/SmartAddModal';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);

  // Modals state
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);
  const [isSmartAddOpen, setIsSmartAddOpen] = useState(false);

  // Load events from local storage on mount
  useEffect(() => {
    const savedEvents = localStorage.getItem('lumina_events');
    if (savedEvents) {
      try {
        setEvents(JSON.parse(savedEvents));
      } catch (e) {
        console.error("Failed to parse events", e);
      }
    }
  }, []);

  // Save events to local storage whenever they change
  useEffect(() => {
    localStorage.setItem('lumina_events', JSON.stringify(events));
  }, [events]);

  const handlePrevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  const handleJumpToToday = () => {
    setCurrentDate(new Date());
  };

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    setSelectedEvent(null);
    setIsEventModalOpen(true);
  };

  const handleEventClick = (e: React.MouseEvent, event: CalendarEvent) => {
    e.stopPropagation();
    setSelectedEvent(event);
    setSelectedDate(new Date(event.start));
    setIsEventModalOpen(true);
  };

  const handleSaveEvent = (event: CalendarEvent) => {
    setEvents(prev => {
      const exists = prev.find(e => e.id === event.id);
      if (exists) {
        return prev.map(e => e.id === event.id ? event : e);
      }
      return [...prev, event];
    });
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  const handleSmartAdd = (eventData: Omit<CalendarEvent, 'id'>) => {
    const newEvent: CalendarEvent = {
        ...eventData,
        id: crypto.randomUUID(),
    };
    setEvents(prev => [...prev, newEvent]);

    // Jump to the new event date
    const newEventDate = new Date(newEvent.start);
    setCurrentDate(new Date(newEventDate.getFullYear(), newEventDate.getMonth(), 1));
  };

  const gridData = generateCalendarGrid(currentDate);

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 text-gray-900 font-sans">
      {/* Header */}
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-200 px-6 py-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl text-white shadow-lg shadow-blue-200">
                <CalendarLogo size={24} />
            </div>
            <h1 className="text-2xl font-bold tracking-tight text-gray-800">Lumina</h1>
        </div>

        <div className="flex items-center gap-6 bg-gray-100/50 p-1.5 rounded-2xl border border-gray-200/50">
            <button 
                onClick={handlePrevMonth}
                className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md"
            >
                <ChevronLeft size={20} />
            </button>
            <span className="text-lg font-semibold w-32 text-center select-none">
                {MONTH_NAMES[currentDate.getMonth()]} {currentDate.getFullYear()}
            </span>
            <button 
                onClick={handleNextMonth}
                className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md"
            >
                <ChevronRight size={20} />
            </button>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
            <button 
                onClick={handleJumpToToday}
                className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors border border-gray-200 bg-white"
            >
                Today
            </button>
            <button 
                onClick={() => setIsSmartAddOpen(true)}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-4 py-2 text-sm font-medium text-white bg-indigo-600 rounded-lg hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100 hover:shadow-lg"
            >
                <Sparkles size={16} />
                <span className="hidden sm:inline">Ask AI</span>
            </button>
            <button 
                onClick={() => {
                    setSelectedDate(new Date());
                    setSelectedEvent(null);
                    setIsEventModalOpen(true);
                }}
                className="flex items-center justify-center p-2 text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-all shadow-md shadow-blue-100 hover:shadow-lg"
            >
                <Plus size={20} />
            </button>
        </div>
      </header>

      {/* Main Grid */}
      <main className="flex-1 p-4 md:p-6 overflow-hidden flex flex-col">
        {/* Days Header */}
