import React, { useState, useEffect } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor } from '../types';
import { formatDateForInput } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon } from 'lucide-react';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date;
  existingEvent?: CalendarEvent | null;
}

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');
  const [start, setStart] = useState('');
  const [end, setEnd] = useState('');
  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [color, setColor] = useState<EventColor>(EventColor.BLUE);
  const [isAllDay, setIsAllDay] = useState(false);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        setStart(existingEvent.start);
        setEnd(existingEvent.end);
        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setColor(existingEvent.color);
        setIsAllDay(existingEvent.isAllDay);
      } else {
        const d = initialDate || new Date();
        const startDate = new Date(d);
        startDate.setHours(9, 0, 0, 0); // Default to 9 AM
        const endDate = new Date(startDate);
        endDate.setHours(10, 0, 0, 0); // Default 1 hour duration

        setTitle('');
        setStart(formatDateForInput(startDate));
        setEnd(formatDateForInput(endDate));
        setDescription('');
        setLocation('');
        setColor(EventColor.BLUE);
        setIsAllDay(false);
      }
    }
  }, [isOpen, existingEvent, initialDate]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start,
      end,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  return (
    <Modal 
        isOpen={isOpen} 
