export const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export const WEEK_DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

export const getDaysInMonth = (year: number, month: number): number => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfMonth = (year: number, month: number): number => {
  return new Date(year, month, 1).getDay();
};

export const isSameDay = (d1: Date, d2: Date): boolean => {
  return (
    d1.getFullYear() === d2.getFullYear() &&
    d1.getMonth() === d2.getMonth() &&
    d1.getDate() === d2.getDate()
  );
};

export const isDateInRange = (
  dateToCheck: Date,
  startDateStr: string,
  endDateStr: string,
  isAllDay: boolean
): boolean => {
  const checkDate = new Date(dateToCheck);
  checkDate.setHours(0, 0, 0, 0);
  const checkTime = checkDate.getTime();

  const dayEnd = new Date(checkDate);
  dayEnd.setHours(23, 59, 59, 999);
  const dayEndTime = dayEnd.getTime();

  const start = new Date(startDateStr);
  const end = new Date(endDateStr);

  if (isAllDay) {
     const s = new Date(start); s.setHours(0, 0, 0, 0);
     const e = new Date(end); e.setHours(0, 0, 0, 0);
     // Inclusive check for dates
     return checkTime >= s.getTime() && checkTime <= e.getTime();
  }

  // Standard overlap check: Start < DayEnd AND End > DayStart
  // If end is exactly midnight of next day, it is > checkTime (Start of Day), so it counts.
  // Standard behavior: 
  // 10:00 Mon -> 00:00 Tue.
  // Mon: 10:00 <= 23:59 AND 00:00(Tue) > 00:00(Mon). True.
  // Tue: 10:00(Mon) <= 23:59(Tue) AND 00:00(Tue) > 00:00(Tue). False. (Strict inequality excludes 00:00 end)
  return start.getTime() <= dayEndTime && end.getTime() > checkTime;
};

export const formatDateForInput = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const formatTime = (isoString: string): string => {
  const date = new Date(isoString);
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

export const generateCalendarGrid = (currentDate: Date): { date: Date; isCurrentMonth: boolean }[] => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  // Previous month days to fill grid
  const daysInPrevMonth = getDaysInMonth(year, month - 1);
  const prevMonthDays = Array.from({ length: firstDay }, (_, i) => {
    return {
      date: new Date(year, month - 1, daysInPrevMonth - firstDay + i + 1),
      isCurrentMonth: false
    };
  });

  // Current month days
  const currentMonthDays = Array.from({ length: daysInMonth }, (_, i) => {
    return {
      date: new Date(year, month, i + 1),
      isCurrentMonth: true
    };
  });

  // Next month days to fill remaining grid (42 cells total for 6 rows)
  const remainingCells = 42 - (prevMonthDays.length + currentMonthDays.length);
  const nextMonthDays = Array.from({ length: remainingCells }, (_, i) => {
    return {
      date: new Date(year, month + 1, i + 1),
      isCurrentMonth: false
    };
  });

  return [...prevMonthDays, ...currentMonthDays, ...nextMonthDays];
};

export const getColorClasses = (color: string) => {
    switch (color) {
        case 'blue': return 'bg-blue-100 text-blue-700 border-blue-200 hover:bg-blue-200';
        case 'red': return 'bg-red-100 text-red-700 border-red-200 hover:bg-red-200';
        case 'green': return 'bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-200';
        case 'yellow': return 'bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-200';
        case 'purple': return 'bg-purple-100 text-purple-700 border-purple-200 hover:bg-purple-200';
        case 'indigo': return 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200';
        case 'pink': return 'bg-pink-100 text-pink-700 border-pink-200 hover:bg-pink-200';
        default: return 'bg-gray-100 text-gray-700 border-gray-200 hover:bg-gray-200';
    }
};

