                    `}
                >
                    {cell.date.getDate()}
                </button>
            )
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor } from '../types';
import { formatDateForInput } from '../utils/dateUtils';
