      start,
      end,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const currentIso = field === 'start' ? start : end;

    // Create new date object from current ISO string to preserve time
    const dateObj = new Date(currentIso);

    // If current ISO is invalid, use newDate with default time
    if (isNaN(dateObj.getTime())) {
        if (field === 'start') {
            newDate.setHours(9, 0, 0, 0);
