        const formatted = formatDateForInput(newDate);
        field === 'start' ? setStart(formatted) : setEnd(formatted);
    } else {
        // Update Year, Month, Date but keep Time
        dateObj.setFullYear(newDate.getFullYear());
        dateObj.setMonth(newDate.getMonth());
        dateObj.setDate(newDate.getDate());

        const formatted = formatDateForInput(dateObj);
        field === 'start' ? setStart(formatted) : setEnd(formatted);
    }

