export const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export const WEEK_DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

export const getDaysInMonth = (year: number, month: number): number => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfMonth = (year: number, month: number): number => {
  return new Date(year, month, 1).getDay();
};

export const isSameDay = (d1: Date, d2: Date): boolean => {
  return (
    d1.getFullYear() === d2.getFullYear() &&
    d1.getMonth() === d2.getMonth() &&
    d1.getDate() === d2.getDate()
  );
};

export const isDateInRange = (
  dateToCheck: Date,
  startDateStr: string,
  endDateStr: string,
  isAllDay: boolean
): boolean => {
  const checkDate = new Date(dateToCheck);
  checkDate.setHours(0, 0, 0, 0);
  const checkTime = checkDate.getTime();

  const dayEnd = new Date(checkDate);
  dayEnd.setHours(23, 59, 59, 999);
  const dayEndTime = dayEnd.getTime();

  const start = new Date(startDateStr);
  const end = new Date(endDateStr);

  if (isAllDay) {
     const s = new Date(start); s.setHours(0, 0, 0, 0);
     const e = new Date(end); e.setHours(0, 0, 0, 0);
     // Inclusive check for dates
     return checkTime >= s.getTime() && checkTime <= e.getTime();
  }

  return start.getTime() <= dayEndTime && end.getTime() > checkTime;
};

export const formatDateForInput = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const toDateString = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
};

export const toTimeString = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const formatFriendlyDate = (dateStr: string): string => {
    if (!dateStr) return '';
    const [y, m, d] = dateStr.split('-').map(Number);
    const date = new Date(y, m - 1, d);
    return date.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric', year: 'numeric' });
};

export const formatTime = (isoString: string): string => {
  const date = new Date(isoString);
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

export const generateCalendarGrid = (currentDate: Date): { date: Date; isCurrentMonth: boolean }[] => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  // Previous month days to fill grid
  const daysInPrevMonth = getDaysInMonth(year, month - 1);
  const prevMonthDays = Array.from({ length: firstDay }, (_, i) => {
    return {
      date: new Date(year, month - 1, daysInPrevMonth - firstDay + i + 1),
      isCurrentMonth: false
    };
  });

  // Current month days
  const currentMonthDays = Array.from({ length: daysInMonth }, (_, i) => {
    return {
      date: new Date(year, month, i + 1),
      isCurrentMonth: true
    };
  });

  // Next month days to fill remaining grid (42 cells total for 6 rows)
  const remainingCells = 42 - (prevMonthDays.length + currentMonthDays.length);
  const nextMonthDays = Array.from({ length: remainingCells }, (_, i) => {
    return {
      date: new Date(year, month + 1, i + 1),
      isCurrentMonth: false
    };
  });

  return [...prevMonthDays, ...currentMonthDays, ...nextMonthDays];
};

export const getColorClasses = (color: string) => {
    switch (color) {
        case 'blue': return 'bg-blue-100 text-blue-700 border-blue-200 hover:bg-blue-200';
        case 'red': return 'bg-red-100 text-red-700 border-red-200 hover:bg-red-200';
        case 'green': return 'bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-200';
        case 'yellow': return 'bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-200';
        case 'purple': return 'bg-purple-100 text-purple-700 border-purple-200 hover:bg-purple-200';
        case 'indigo': return 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200';
        case 'pink': return 'bg-pink-100 text-pink-700 border-pink-200 hover:bg-pink-200';
        default: return 'bg-gray-100 text-gray-700 border-gray-200 hover:bg-gray-200';
    }
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor } from '../types';
import { toDateString, toTimeString, formatFriendlyDate } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date;
  existingEvent?: CalendarEvent | null;
}

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');

  // Separate date and time states
  const [startDate, setStartDate] = useState('');
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState('');
  const [endTime, setEndTime] = useState('');

  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [color, setColor] = useState<EventColor>(EventColor.BLUE);
  const [isAllDay, setIsAllDay] = useState(false);

  // State to track which date picker is active
  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);

        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));

        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setColor(existingEvent.color);
        setIsAllDay(existingEvent.isAllDay);
      } else {
        const d = initialDate || new Date();
        const s = new Date(d);
        // Default to current time or next hour if created from "Today" button, 
        // but if created from grid click usually it's set to specific date 00:00 or current time
        // Let's default to next hour if it's "Today", or 09:00 if it's a future date
        const isToday = d.toDateString() === new Date().toDateString();

        if (isToday) {
             const now = new Date();
             now.setMinutes(0);
             now.setHours(now.getHours() + 1);
             s.setHours(now.getHours(), 0, 0, 0);
        } else {
             s.setHours(9, 0, 0, 0);
        }

        const e = new Date(s);
        e.setHours(s.getHours() + 1);

        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));

        setTitle('');
        setDescription('');
        setLocation('');
        setColor(EventColor.BLUE);
        setIsAllDay(false);
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Construct ISO strings
    // If All Day, we can default time to 00:00 for start and 23:59 for end or just 00:00
    // The utils use 00:00 check for isAllDay, so 00:00 is fine.

    const sTime = isAllDay ? '00:00' : (startTime || '00:00');
    const eTime = isAllDay ? '00:00' : (endTime || '00:00');

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    // Ensure Start < End if not all day?
    // The app allows end < start usually but it's bad UX. 
    // Basic validation could be added here but keeping it simple as per prompt.

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        // Optional: auto-update end date if it becomes before start date
        if (new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        if (spaceBelow < 320) {
            setCalendarPos('top');
        } else {
            setCalendarPos('bottom');
        }
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">

        {/* Title */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        {/* Date & Time Section */}
        <div className="grid grid-cols-1 gap-3">
             {/* Start Row */}
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div className="relative group flex-grow" ref={startDateRef}>
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <input
                            type="text"
                            readOnly
                            required
                            value={formatFriendlyDate(startDate)}
                            onClick={() => openCalendar('start')}
                            className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer select-none"
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={new Date(startDate)} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>

                     {/* Time Input (Optional) */}
                     {!isAllDay && (
                        <div className="relative w-32">
                             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                                <Clock size={16} />
                            </div>
                            <input
                                type="time"
                                value={startTime}
                                onChange={(e) => setStartTime(e.target.value)}
                                className="w-full pl-8 pr-2 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
                            />
                        </div>
                     )}
                </div>
            </div>

            {/* End Row */}
            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div className="relative group flex-grow" ref={endDateRef}>
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <input
                            type="text"
                            readOnly
                            required
                            value={formatFriendlyDate(endDate)}
                            onClick={() => openCalendar('end')}
                            className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer select-none"
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={new Date(endDate)} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>

                    {/* Time Input (Optional) */}
                    {!isAllDay && (
                         <div className="relative w-32">
                             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                                <Clock size={16} />
                            </div>
                            <input
                                type="time"
                                value={endTime}
                                onChange={(e) => setEndTime(e.target.value)}
                                className="w-full pl-8 pr-2 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
                            />
                        </div>
                    )}
                </div>
            </div>
        </div>

        {/* All Day Toggle */}
        <div className="flex items-center gap-2">
            <input 
                type="checkbox" 
                id="isAllDay"
                checked={isAllDay}
                onChange={(e) => setIsAllDay(e.target.checked)}
                className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500 cursor-pointer"
            />
            <label htmlFor="isAllDay" className="text-sm text-gray-700 cursor-pointer select-none">All day event</label>
        </div>

        {/* Location */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        {/* Description */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        {/* Color Picker */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Color</label>
            <div className="flex gap-2 flex-wrap">
                {Object.values(EventColor).map((c) => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setColor(c)}
                        className={`w-6 h-6 rounded-full transition-transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-gray-300 ${color === c ? 'ring-2 ring-offset-1 ring-gray-400 scale-110' : ''}`}
                        style={{ backgroundColor: `var(--color-${c}-400, ${c})` }}
                    />
                ))}
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div></div>}

            <div className="flex gap-2">
                <button
                    type="button"
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                >
                    Cancel
                </button>
                <button
                    type="submit"
                    className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                >
                    Save
                </button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

export const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export const WEEK_DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

export const getDaysInMonth = (year: number, month: number): number => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfMonth = (year: number, month: number): number => {
  return new Date(year, month, 1).getDay();
};

export const isSameDay = (d1: Date, d2: Date): boolean => {
  return (
    d1.getFullYear() === d2.getFullYear() &&
    d1.getMonth() === d2.getMonth() &&
    d1.getDate() === d2.getDate()
  );
};

export const isDateInRange = (
  dateToCheck: Date,
  startDateStr: string,
  endDateStr: string,
  isAllDay: boolean
): boolean => {
  const checkDate = new Date(dateToCheck);
  checkDate.setHours(0, 0, 0, 0);
  const checkTime = checkDate.getTime();

  const dayEnd = new Date(checkDate);
  dayEnd.setHours(23, 59, 59, 999);
  const dayEndTime = dayEnd.getTime();

  const start = new Date(startDateStr);
  const end = new Date(endDateStr);

  if (isAllDay) {
     const s = new Date(start); s.setHours(0, 0, 0, 0);
     const e = new Date(end); e.setHours(0, 0, 0, 0);
     // Inclusive check for dates
     return checkTime >= s.getTime() && checkTime <= e.getTime();
  }

  return start.getTime() <= dayEndTime && end.getTime() > checkTime;
};

export const formatDateForInput = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const toDateString = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
};

export const toTimeString = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const formatFriendlyDate = (dateStr: string): string => {
    if (!dateStr) return '';
    const [y, m, d] = dateStr.split('-').map(Number);
    const date = new Date(y, m - 1, d);
    const pad = (n: number) => n.toString().padStart(2, '0');
    return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()}`;
};

export const formatTime = (isoString: string): string => {
  const date = new Date(isoString);
  return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

export const generateCalendarGrid = (currentDate: Date): { date: Date; isCurrentMonth: boolean }[] => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  // Previous month days to fill grid
  const daysInPrevMonth = getDaysInMonth(year, month - 1);
  const prevMonthDays = Array.from({ length: firstDay }, (_, i) => {
    return {
      date: new Date(year, month - 1, daysInPrevMonth - firstDay + i + 1),
      isCurrentMonth: false
    };
  });

  // Current month days
  const currentMonthDays = Array.from({ length: daysInMonth }, (_, i) => {
    return {
      date: new Date(year, month, i + 1),
      isCurrentMonth: true
    };
  });

  // Next month days to fill remaining grid (42 cells total for 6 rows)
  const remainingCells = 42 - (prevMonthDays.length + currentMonthDays.length);
  const nextMonthDays = Array.from({ length: remainingCells }, (_, i) => {
    return {
      date: new Date(year, month + 1, i + 1),
      isCurrentMonth: false
    };
  });

  return [...prevMonthDays, ...currentMonthDays, ...nextMonthDays];
};

export const getColorClasses = (color: string) => {
    switch (color) {
        case 'blue': return 'bg-blue-100 text-blue-700 border-blue-200 hover:bg-blue-200';
        case 'red': return 'bg-red-100 text-red-700 border-red-200 hover:bg-red-200';
        case 'green': return 'bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-200';
        case 'yellow': return 'bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-200';
        case 'purple': return 'bg-purple-100 text-purple-700 border-purple-200 hover:bg-purple-200';
        case 'indigo': return 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200';
        case 'pink': return 'bg-pink-100 text-pink-700 border-pink-200 hover:bg-pink-200';
        default: return 'bg-gray-100 text-gray-700 border-gray-200 hover:bg-gray-200';
    }
