import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { generateCalendarGrid, MONTH_NAMES, WEEK_DAYS, isSameDay } from '../utils/dateUtils';

interface MiniCalendarProps {
  initialDate: Date;
  onSelectDate: (date: Date) => void;
  onClose: () => void;
}

export const MiniCalendar: React.FC<MiniCalendarProps> = ({ initialDate, onSelectDate, onClose }) => {
  // If initialDate is invalid (empty input), default view to today
  const safeInitialDate = isNaN(initialDate.getTime()) ? new Date() : initialDate;
  const [viewDate, setViewDate] = useState(new Date(safeInitialDate));
  const calendarRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (!isNaN(initialDate.getTime())) {
        setViewDate(new Date(initialDate));
    }
  }, [initialDate]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (calendarRef.current && !calendarRef.current.contains(event.target as Node)) {
        onClose();
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, [onClose]);

  const handlePrevMonth = (e: React.MouseEvent) => {
    e.stopPropagation();
    setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() - 1, 1));
  };

  const handleNextMonth = (e: React.MouseEvent) => {
    e.stopPropagation();
    setViewDate(new Date(viewDate.getFullYear(), viewDate.getMonth() + 1, 1));
  };

  const grid = generateCalendarGrid(viewDate);

  return (
    <div ref={calendarRef} className="bg-white rounded-xl shadow-xl border border-gray-100 p-3 w-64 select-none">
      <div className="flex items-center justify-between mb-2">
        <button type="button" onClick={handlePrevMonth} className="p-1 hover:bg-gray-100 rounded-lg text-gray-600 transition-colors">
            <ChevronLeft size={16} />
        </button>
        <span className="text-sm font-semibold text-gray-800">
            {MONTH_NAMES[viewDate.getMonth()]} {viewDate.getFullYear()}
        </span>
        <button type="button" onClick={handleNextMonth} className="p-1 hover:bg-gray-100 rounded-lg text-gray-600 transition-colors">
            <ChevronRight size={16} />
        </button>
      </div>
      <div className="grid grid-cols-7 gap-1 mb-1">
        {WEEK_DAYS.map(d => (
            <div key={d} className="text-center text-[10px] font-medium text-gray-400">
                {d.charAt(0)}
            </div>
        ))}
      </div>
      <div className="grid grid-cols-7 gap-1">
        {grid.map((cell, idx) => {
            const isValidInitial = !isNaN(initialDate.getTime());
            const isSelected = isValidInitial && isSameDay(cell.date, initialDate);
            const isToday = isSameDay(cell.date, new Date());

            return (
                <button
                    key={idx}
                    type="button"
                    onClick={(e) => {
                        e.stopPropagation();
                        onSelectDate(cell.date);
                    }}
                    className={`
                        h-7 w-7 rounded-lg flex items-center justify-center text-xs transition-all
                        ${!cell.isCurrentMonth ? 'text-gray-300' : 'text-gray-700 hover:bg-gray-100'}
                        ${isSelected ? 'bg-blue-600 text-white hover:bg-blue-700 shadow-sm' : ''}
                        ${!isSelected && isToday ? 'text-blue-600 font-semibold bg-blue-50 ring-1 ring-blue-100' : ''}
                    `}
                >
                    {cell.date.getDate()}
                </button>
            )
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor } from '../types';
import { toDateString, toTimeString, formatFriendlyDate } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');

  // Separate date and time states
  const [startDate, setStartDate] = useState('');
  const [startTime, setStartTime] = useState('');
  const [endDate, setEndDate] = useState('');
  const [endTime, setEndTime] = useState('');

  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [color, setColor] = useState<EventColor>(EventColor.BLUE);
  const [isAllDay, setIsAllDay] = useState(false);

  // State to track which date picker is active
  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);

        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));

        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setColor(existingEvent.color);
        setIsAllDay(existingEvent.isAllDay);
      } else {
        // If created via day click (initialDate provided), pre-fill.
        // If created via generic button (initialDate null), leave empty.
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); // Default start time
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); // Default end time

             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }

        setTitle('');
        setDescription('');
        setLocation('');
        setColor(EventColor.BLUE);
        setIsAllDay(false);
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!startDate || !endDate) {
        // Since fields are readOnly for custom picker, native required check might not feel enough for UX
        // But the browser should stop submission if required is set on input.
        // Just to be safe:
        return; 
    }

    const sTime = isAllDay ? '00:00' : (startTime || '00:00');
    const eTime = isAllDay ? '00:00' : (endTime || '00:00');

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);
    if (field === 'start') {
        setStartDate(dateStr);
        // Optional: if End Date is empty, or before Start Date, update it
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        if (spaceBelow < 320) {
            setCalendarPos('top');
        } else {
            setCalendarPos('bottom');
        }
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">

        {/* Title */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        {/* Date & Time Section */}
        <div className="grid grid-cols-1 gap-3">
             {/* Start Row */}
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div className="relative group flex-grow" ref={startDateRef}>
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <input
                            type="text"
                            readOnly
                            required
                            placeholder="DD/MM/YYYY"
                            value={formatFriendlyDate(startDate)}
                            onClick={() => openCalendar('start')}
                            className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer select-none placeholder-gray-400"
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={new Date(startDate)} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>

                     {/* Time Input (Optional) */}
                     {!isAllDay && (
                        <div className="relative w-32">
                             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                                <Clock size={16} />
                            </div>
                            <input
                                type="time"
                                value={startTime}
                                onChange={(e) => setStartTime(e.target.value)}
                                className="w-full pl-8 pr-2 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
                            />
                        </div>
                     )}
                </div>
            </div>

            {/* End Row */}
            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div className="relative group flex-grow" ref={endDateRef}>
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <input
                            type="text"
                            readOnly
                            required
                            placeholder="DD/MM/YYYY"
                            value={formatFriendlyDate(endDate)}
                            onClick={() => openCalendar('end')}
                            className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none cursor-pointer select-none placeholder-gray-400"
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={new Date(endDate)} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>

                    {/* Time Input (Optional) */}
                    {!isAllDay && (
                         <div className="relative w-32">
                             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                                <Clock size={16} />
                            </div>
                            <input
                                type="time"
                                value={endTime}
                                onChange={(e) => setEndTime(e.target.value)}
                                className="w-full pl-8 pr-2 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none appearance-none"
                            />
                        </div>
                    )}
                </div>
            </div>
        </div>

        {/* All Day Toggle */}
        <div className="flex items-center gap-2">
            <input 
                type="checkbox" 
                id="isAllDay"
                checked={isAllDay}
                onChange={(e) => setIsAllDay(e.target.checked)}
                className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500 cursor-pointer"
            />
            <label htmlFor="isAllDay" className="text-sm text-gray-700 cursor-pointer select-none">All day event</label>
        </div>

        {/* Location */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        {/* Description */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        {/* Color Picker */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Color</label>
            <div className="flex gap-2 flex-wrap">
                {Object.values(EventColor).map((c) => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setColor(c)}
                        className={`w-6 h-6 rounded-full transition-transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-gray-300 ${color === c ? 'ring-2 ring-offset-1 ring-gray-400 scale-110' : ''}`}
                        style={{ backgroundColor: `var(--color-${c}-400, ${c})` }}
                    />
                ))}
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div></div>}

            <div className="flex gap-2">
                <button
                    type="button"
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                >
                    Cancel
                </button>
                <button
                    type="submit"
                    className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                >
                    Save
                </button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, Plus, Calendar as CalendarLogo } from 'lucide-react';
import { CalendarEvent, EventColor, DayData } from './types';
import { 
    generateCalendarGrid, 
    MONTH_NAMES, 
    WEEK_DAYS, 
    isSameDay, 
    isDateInRange,
    formatTime,
    getColorClasses 
} from './utils/dateUtils';
import { EventModal } from './components/EventModal';

const App: React.FC = () => {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [events, setEvents] = useState<CalendarEvent[]>([]);
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [selectedEvent, setSelectedEvent] = useState<CalendarEvent | null>(null);

  // Modals state
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);

  // Load events from local storage on mount
  useEffect(() => {
    const savedEvents = localStorage.getItem('lumina_events');
    if (savedEvents) {
      try {
        setEvents(JSON.parse(savedEvents));
      } catch (e) {
        console.error("Failed to parse events", e);
      }
    }
  }, []);

  // Save events to local storage whenever they change
  useEffect(() => {
    localStorage.setItem('lumina_events', JSON.stringify(events));
  }, [events]);

  const handlePrevMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const handleNextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  const handleJumpToToday = () => {
    setCurrentDate(new Date());
  };

  const handleDateClick = (date: Date) => {
    setSelectedDate(date);
    setSelectedEvent(null);
    setIsEventModalOpen(true);
  };

  const handleEventClick = (e: React.MouseEvent, event: CalendarEvent) => {
    e.stopPropagation();
    setSelectedEvent(event);
    setSelectedDate(new Date(event.start));
    setIsEventModalOpen(true);
  };

  const handleSaveEvent = (event: CalendarEvent) => {
    setEvents(prev => {
      const exists = prev.find(e => e.id === event.id);
      if (exists) {
        return prev.map(e => e.id === event.id ? event : e);
      }
      return [...prev, event];
    });
  };

  const handleDeleteEvent = (id: string) => {
    setEvents(prev => prev.filter(e => e.id !== id));
  };

  const gridData = generateCalendarGrid(currentDate);

  return (
    <div className="min-h-screen flex flex-col bg-gray-50 text-gray-900 font-sans">
      {/* Header */}
      <header className="sticky top-0 z-30 bg-white/80 backdrop-blur-md border-b border-gray-200 px-6 py-4 flex flex-col md:flex-row items-center justify-between gap-4 shadow-sm">
        <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-xl text-white shadow-lg shadow-blue-200">
                <CalendarLogo size={24} />
            </div>
            <h1 className="text-2xl font-bold tracking-tight text-gray-800">Lumina</h1>
        </div>

        <div className="flex items-center gap-6 bg-gray-100/50 p-1.5 rounded-2xl border border-gray-200/50">
            <button 
                onClick={handlePrevMonth}
                className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md"
            >
                <ChevronLeft size={20} />
            </button>
            <span className="text-lg font-semibold w-32 text-center select-none">
                {MONTH_NAMES[currentDate.getMonth()]} {currentDate.getFullYear()}
            </span>
            <button 
                onClick={handleNextMonth}
                className="p-2 hover:bg-white rounded-xl text-gray-600 transition-all shadow-sm hover:shadow-md"
            >
                <ChevronRight size={20} />
            </button>
        </div>

        <div className="flex items-center gap-3 w-full md:w-auto">
            <button 
                onClick={handleJumpToToday}
                className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors border border-gray-200 bg-white"
            >
                Today
            </button>
            <button 
                onClick={() => {
                    setSelectedDate(null);
                    setSelectedEvent(null);
                    setIsEventModalOpen(true);
                }}
                className="flex items-center justify-center p-2 text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-all shadow-md shadow-blue-100 hover:shadow-lg"
            >
                <Plus size={20} />
            </button>
        </div>
      </header>

      {/* Main Grid */}
      <main className="flex-1 p-4 md:p-6 overflow-hidden flex flex-col">
        {/* Days Header */}
        <div className="grid grid-cols-7 mb-4">
            {WEEK_DAYS.map(day => (
                <div key={day} className="text-center text-sm font-semibold text-gray-400 uppercase tracking-wider">
                    {day}
                </div>
            ))}
        </div>

        {/* Calendar Grid */}
        <div className="flex-1 grid grid-cols-7 grid-rows-6 gap-2 md:gap-4 min-h-[600px]">
            {gridData.map((cell, index) => {
                const isToday = isSameDay(cell.date, new Date());
                const dayEvents = events.filter(e => isDateInRange(cell.date, e.start, e.end, e.isAllDay))
                                        .sort((a, b) => new Date(a.start).getTime() - new Date(b.start).getTime());

                return (
                    <div 
                        key={index} 
                        onClick={() => handleDateClick(cell.date)}
                        className={`
                            relative bg-white rounded-2xl p-2 border border-gray-100 
                            transition-all hover:shadow-md cursor-pointer flex flex-col gap-1 overflow-hidden group
                            ${!cell.isCurrentMonth ? 'bg-gray-50/50 text-gray-400' : 'text-gray-700'}
                            ${isToday ? 'ring-2 ring-blue-500 ring-offset-2' : ''}
                        `}
                    >
                        <div className="flex justify-between items-start">
                            <span className={`
                                text-sm font-medium w-7 h-7 flex items-center justify-center rounded-full
                                ${isToday ? 'bg-blue-600 text-white' : ''}
                            `}>
                                {cell.date.getDate()}
                            </span>
                        </div>

                        {/* Events List */}
                        <div className="flex-1 flex flex-col gap-1 overflow-y-auto custom-scrollbar mt-1">
                            {dayEvents.map(event => (
                                <div 
                                    key={event.id}
                                    onClick={(e) => handleEventClick(e, event)}
                                    className={`
                                        text-xs px-2 py-1 rounded-md truncate font-medium border-l-2 transition-transform hover:scale-[1.02]
                                        ${getColorClasses(event.color)}
                                    `}
                                    title={`${event.title} (${event.isAllDay ? 'All Day' : formatTime(event.start)})`}
                                >
                                    {event.isAllDay ? '' : <span className="opacity-75 mr-1 text-[10px]">{formatTime(event.start)}</span>}
                                    {event.title}
                                </div>
                            ))}
                        </div>

                        {/* Hover Plus Button (Desktop) */}
                        <div className="absolute bottom-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity hidden md:block">
                            <div className="bg-gray-100 p-1 rounded-full text-gray-400 hover:text-blue-600 hover:bg-blue-50">
                                <Plus size={14} />
                            </div>
                        </div>
                    </div>
                );
            })}
        </div>
      </main>

      {/* Modals */}
      <EventModal 
        isOpen={isEventModalOpen}
        onClose={() => setIsEventModalOpen(false)}
        onSave={handleSaveEvent}
        onDelete={handleDeleteEvent}
        initialDate={selectedDate}
        existingEvent={selectedEvent}
      />
    </div>
  );
};

export default App;

export const MONTH_NAMES = [
  "January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];

export const WEEK_DAYS = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

export const getDaysInMonth = (year: number, month: number): number => {
  return new Date(year, month + 1, 0).getDate();
};

export const getFirstDayOfMonth = (year: number, month: number): number => {
  return new Date(year, month, 1).getDay();
};

export const isSameDay = (d1: Date, d2: Date): boolean => {
  return (
    d1.getFullYear() === d2.getFullYear() &&
    d1.getMonth() === d2.getMonth() &&
    d1.getDate() === d2.getDate()
  );
};

export const isDateInRange = (
  dateToCheck: Date,
  startDateStr: string,
  endDateStr: string,
  isAllDay: boolean
): boolean => {
  const checkDate = new Date(dateToCheck);
  checkDate.setHours(0, 0, 0, 0);
  const checkTime = checkDate.getTime();

  const dayEnd = new Date(checkDate);
  dayEnd.setHours(23, 59, 59, 999);
  const dayEndTime = dayEnd.getTime();

  const start = new Date(startDateStr);
  const end = new Date(endDateStr);

  if (isAllDay) {
     const s = new Date(start); s.setHours(0, 0, 0, 0);
     const e = new Date(end); e.setHours(0, 0, 0, 0);
     // Inclusive check for dates
     return checkTime >= s.getTime() && checkTime <= e.getTime();
  }

  return start.getTime() <= dayEndTime && end.getTime() > checkTime;
};

export const formatDateForInput = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}T${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const toDateString = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
};

export const toTimeString = (date: Date): string => {
  const pad = (n: number) => n.toString().padStart(2, '0');
  return `${pad(date.getHours())}:${pad(date.getMinutes())}`;
};

export const formatFriendlyDate = (dateStr: string): string => {
    if (!dateStr) return '';
    const [y, m, d] = dateStr.split('-').map(Number);
    const date = new Date(y, m - 1, d);
    const pad = (n: number) => n.toString().padStart(2, '0');
    return `${pad(date.getDate())}/${pad(date.getMonth() + 1)}/${date.getFullYear()}`;
};

export const formatTime = (isoString: string): string => {
  const date = new Date(isoString);
  return date.toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', hour12: false });
};

export const generateCalendarGrid = (currentDate: Date): { date: Date; isCurrentMonth: boolean }[] => {
  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();

  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getFirstDayOfMonth(year, month);

  // Previous month days to fill grid
  const daysInPrevMonth = getDaysInMonth(year, month - 1);
  const prevMonthDays = Array.from({ length: firstDay }, (_, i) => {
    return {
      date: new Date(year, month - 1, daysInPrevMonth - firstDay + i + 1),
      isCurrentMonth: false
    };
  });

  // Current month days
  const currentMonthDays = Array.from({ length: daysInMonth }, (_, i) => {
    return {
      date: new Date(year, month, i + 1),
      isCurrentMonth: true
    };
  });

  // Next month days to fill remaining grid (42 cells total for 6 rows)
  const remainingCells = 42 - (prevMonthDays.length + currentMonthDays.length);
  const nextMonthDays = Array.from({ length: remainingCells }, (_, i) => {
    return {
      date: new Date(year, month + 1, i + 1),
      isCurrentMonth: false
    };
  });

  return [...prevMonthDays, ...currentMonthDays, ...nextMonthDays];
};

export const getColorClasses = (color: string) => {
    switch (color) {
        case 'blue': return 'bg-blue-100 text-blue-700 border-blue-200 hover:bg-blue-200';
        case 'red': return 'bg-red-100 text-red-700 border-red-200 hover:bg-red-200';
        case 'green': return 'bg-emerald-100 text-emerald-700 border-emerald-200 hover:bg-emerald-200';
        case 'yellow': return 'bg-amber-100 text-amber-700 border-amber-200 hover:bg-amber-200';
        case 'purple': return 'bg-purple-100 text-purple-700 border-purple-200 hover:bg-purple-200';
        case 'indigo': return 'bg-indigo-100 text-indigo-700 border-indigo-200 hover:bg-indigo-200';
        case 'pink': return 'bg-pink-100 text-pink-700 border-pink-200 hover:bg-pink-200';
        default: return 'bg-gray-100 text-gray-700 border-gray-200 hover:bg-gray-200';
    }
};

