  GRAY = 'gray'
}

export interface DayData {
  date: Date;
  isCurrentMonth: boolean;
  isToday: boolean;
  events: CalendarEvent[];
}

// AI Service has been disabled.
export const parseEventWithGemini = async (text: string) => {
  return null;
