    }

    const sTime = isAllDay ? '00:00' : (startTime || '00:00');
    const eTime = isAllDay ? '00:00' : (endTime || '00:00');

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);

    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        if (spaceBelow < 320) {
            setCalendarPos('top');
        } else {
            setCalendarPos('bottom');
        }
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">

        {/* Title */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        {/* Date & Time Section */}
        <div className="grid grid-cols-1 gap-3">
             {/* Start Row */}
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                // Smart logic: if end date < start date, sync it
                                if (!endDate || new Date(iso) > new Date(endDate)) {
                                    setEndDate(iso);
                                }
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => {
                                if (isAllDay) {
                                    endDayInputRef.current?.focus();
                                } else {
                                    startHourRef.current?.focus();
                                }
                            }}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>

                     {/* Time Input (Custom) */}
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            {/* End Row */}
            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => {
                                if (!isAllDay) {
                                    endHourRef.current?.focus();
                                }
                            }}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>

                    {/* Time Input (Custom) */}
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        {/* All Day Toggle */}
        <div className="flex items-center gap-2">
            <input 
                type="checkbox" 
                id="isAllDay"
                checked={isAllDay}
                onChange={(e) => setIsAllDay(e.target.checked)}
                className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500 cursor-pointer"
            />
            <label htmlFor="isAllDay" className="text-sm text-gray-700 cursor-pointer select-none">All day event</label>
        </div>

        {/* Location */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        {/* Description */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        {/* Color Picker */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Color</label>
            <div className="flex gap-2 flex-wrap">
                {Object.values(EventColor).map((c) => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setColor(c)}
                        className={`w-6 h-6 rounded-full transition-transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-gray-300 ${color === c ? 'ring-2 ring-offset-1 ring-gray-400 scale-110' : ''}`}
                        style={{ backgroundColor: `var(--color-${c}-400, ${c})` }}
                    />
                ))}
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div></div>}

            <div className="flex gap-2">
                <button
                    type="button"
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                >
                    Cancel
                </button>
                <button
                    type="submit"
                    className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                >
                    Save
                </button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; // Ref for the Day input (entry point)
    onComplete?: () => void; // Called when Year is filled
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    // Local state for inputs to allow typing freely
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);

    // Sync local state with prop when prop changes (e.g. calendar selection)
    useEffect(() => {
        if (dateStr) {
            const [year, month, day] = dateStr.split('-');

            // Compare numerically to avoid overwriting "1" with "01" while typing
            const dInt = parseInt(day || '0', 10);
            const mInt = parseInt(month || '0', 10);
            const yInt = parseInt(year || '0', 10);

            const curDInt = parseInt(d || '0', 10);
            const curMInt = parseInt(m || '0', 10);
            const curYInt = parseInt(y || '0', 10);

            // Update if the actual values differ (external update)
            // Or if the string is empty but we have a value (initial load)
            if (yInt !== curYInt || mInt !== curMInt || dInt !== curDInt || (d === '' && day)) {
                 setY(year);
                 setM(month);
                 setD(day);
            }
        } else {
            setD(''); setM(''); setY('');
        }
        // We purposefully rely on dateStr changes. 
        // Adding d, m, y to deps would cause loops.
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        // Only trigger onChange if we have a potentially valid full date
        if (day.length === 2 && month.length === 2 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             // Validate date exists (e.g. not 31st Feb)
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        // Allow digits only
        if (!/^\d*$/.test(val)) return;

        // Handle logic where user types into a full field (e.g. "01" -> "012")
        // We take the last 2 digits if length > 2, assuming user wants to overwrite
        if (val.length > 2) {
             val = val.slice(-2);
        }

        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;

        if (val.length > 2) {
            val = val.slice(-2);
        }

        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        if (val.length > 4) val = val.slice(0, 4);

        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        if (d.length === 1) {
            const newVal = d.padStart(2, '0');
            setD(newVal);
            updateDate(newVal, m, y);
        }
    };

    const handleMonthBlur = () => {
        if (m.length === 1) {
             const newVal = m.padStart(2, '0');
             setM(newVal);
             updateDate(d, newVal, y);
        }
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

const TimeSelect: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
}> = ({ value, onChange, inputRef, onComplete }) => {
    const [h = '00', m = '00'] = (value || '00:00').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);

    const updateTime = (newH: string, newM: string) => {
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;

        if (val.length > 2) val = val.slice(-2);

        updateTime(val, m);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        let val = parseInt(h, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(23, Math.max(0, val));
        updateTime(val.toString().padStart(2, '0'), m);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;

        if (val.length > 2) val = val.slice(-2);

        updateTime(h, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        let val = parseInt(m, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(59, Math.max(0, val));
        updateTime(h, val.toString().padStart(2, '0'));
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={h} 
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={m} 
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');

  // Separate date and time states
  const [startDate, setStartDate] = useState(''); // ISO YYYY-MM-DD
  const [startTime, setStartTime] = useState('');

  const [endDate, setEndDate] = useState(''); // ISO YYYY-MM-DD
  const [endTime, setEndTime] = useState('');

  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [color, setColor] = useState<EventColor>(EventColor.BLUE);
  const [isAllDay, setIsAllDay] = useState(false);

  // State to track which date picker is active
  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  // Refs for chaining focus
  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);

  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);

        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));

        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setColor(existingEvent.color);
        setIsAllDay(existingEvent.isAllDay);
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 

             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }

        setTitle('');
        setDescription('');
        setLocation('');
        setColor(EventColor.BLUE);
        setIsAllDay(false);
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  // Handle clicking outside of active date field to close calendar
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };

    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!startDate || !endDate) {
        return; 
    }

    const sTime = isAllDay ? '00:00' : (startTime || '00:00');
    const eTime = isAllDay ? '00:00' : (endTime || '00:00');

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);

    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        if (spaceBelow < 320) {
            setCalendarPos('top');
        } else {
            setCalendarPos('bottom');
        }
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">

        {/* Title */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        {/* Date & Time Section */}
        <div className="grid grid-cols-1 gap-3">
             {/* Start Row */}
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                // Smart logic: if end date < start date, sync it
                                if (!endDate || new Date(iso) > new Date(endDate)) {
                                    setEndDate(iso);
                                }
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => {
                                if (isAllDay) {
                                    endDayInputRef.current?.focus();
                                } else {
                                    startHourRef.current?.focus();
                                }
                            }}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>

                     {/* Time Input (Custom) */}
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            {/* End Row */}
            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => {
                                if (!isAllDay) {
                                    endHourRef.current?.focus();
                                }
                            }}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>

                    {/* Time Input (Custom) */}
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        {/* All Day Toggle */}
        <div className="flex items-center gap-2">
            <input 
                type="checkbox" 
                id="isAllDay"
                checked={isAllDay}
                onChange={(e) => setIsAllDay(e.target.checked)}
                className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500 cursor-pointer"
            />
            <label htmlFor="isAllDay" className="text-sm text-gray-700 cursor-pointer select-none">All day event</label>
        </div>

        {/* Location */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        {/* Description */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        {/* Color Picker */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Color</label>
            <div className="flex gap-2 flex-wrap">
                {Object.values(EventColor).map((c) => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setColor(c)}
                        className={`w-6 h-6 rounded-full transition-transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-gray-300 ${color === c ? 'ring-2 ring-offset-1 ring-gray-400 scale-110' : ''}`}
                        style={{ backgroundColor: `var(--color-${c}-400, ${c})` }}
                    />
                ))}
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div></div>}

            <div className="flex gap-2">
                <button
                    type="button"
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                >
                    Cancel
                </button>
                <button
                    type="submit"
                    className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                >
                    Save
                </button>
            </div>
        </div>
      </form>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Modal } from './Modal';
import { CalendarEvent, EventColor } from '../types';
import { toDateString, toTimeString } from '../utils/dateUtils';
import { Clock, MapPin, AlignLeft, Type, Calendar as CalendarIcon } from 'lucide-react';
import { MiniCalendar } from './MiniCalendar';

interface EventModalProps {
  isOpen: boolean;
  onClose: () => void;
  onSave: (event: CalendarEvent) => void;
  onDelete: (id: string) => void;
  initialDate?: Date | null;
  existingEvent?: CalendarEvent | null;
}

interface DateInputProps {
    dateStr: string; // ISO YYYY-MM-DD
    onChange: (iso: string) => void;
    onFocus: () => void;
    inputRef?: React.RefObject<HTMLInputElement | null>; // Ref for the Day input (entry point)
    onComplete?: () => void; // Called when Year is filled
}

const DateInput: React.FC<DateInputProps> = ({ dateStr, onChange, onFocus, inputRef, onComplete }) => {
    // Local state for inputs to allow typing freely
    const [d, setD] = useState('');
    const [m, setM] = useState('');
    const [y, setY] = useState('');

    const monthRef = useRef<HTMLInputElement>(null);
    const yearRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Sync local state with prop when prop changes (e.g. calendar selection)
    useEffect(() => {
        // Do not overwrite user input while they are typing (focused)
        if (isFocused.current) return;

        if (dateStr) {
            const [year, month, day] = dateStr.split('-');
            setY(year);
            setM(month);
            setD(day);
        } else {
            setD(''); setM(''); setY('');
        }
    }, [dateStr]);

    const updateDate = (day: string, month: string, year: string) => {
        // Only trigger onChange if we have a potentially valid full date
        if (day.length === 2 && month.length === 2 && year.length === 4) {
             const newDate = new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
             // Validate date exists (e.g. not 31st Feb)
             if (newDate.getDate() === parseInt(day) && newDate.getMonth() === parseInt(month) - 1) {
                 onChange(toDateString(newDate));
             }
        }
    };

    const handleDayChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;

        // Strategy: If length > 2, keep the last 2 digits (typing forward)
        // This handles "05" -> type "1" -> "051" -> "51" -> type "2" -> "12"
        if (val.length > 2) {
             val = val.slice(-2);
        }

        setD(val);
        updateDate(val, m, y);
        if (val.length === 2) monthRef.current?.focus();
    };

    const handleMonthChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;

        if (val.length > 2) {
            val = val.slice(-2);
        }

        setM(val);
        updateDate(d, val, y);
        if (val.length === 2) yearRef.current?.focus();
    };

    const handleYearChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;
        if (val.length > 4) val = val.slice(0, 4);

        setY(val);
        updateDate(d, m, val);
        if (val.length === 4 && onComplete) {
            onComplete();
        }
    };

    const handleDayBlur = () => {
        isFocused.current = false;
        if (d.length === 1) {
            const newVal = d.padStart(2, '0');
            setD(newVal);
            updateDate(newVal, m, y);
        }
    };

    const handleMonthBlur = () => {
        isFocused.current = false;
        if (m.length === 1) {
             const newVal = m.padStart(2, '0');
             setM(newVal);
             updateDate(d, newVal, y);
        }
    };

    const handleYearBlur = () => {
        isFocused.current = false;
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
        onFocus();
    };

    return (
        <div className="flex items-center gap-0.5 w-full h-full">
            <input
                ref={inputRef}
                type="text"
                placeholder="DD"
                value={d}
                onChange={handleDayChange}
                onBlur={handleDayBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={monthRef}
                type="text"
                placeholder="MM"
                value={m}
                onChange={handleMonthChange}
                onBlur={handleMonthBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-8 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
            <span className="text-gray-400 select-none">/</span>
            <input
                ref={yearRef}
                type="text"
                placeholder="YYYY"
                maxLength={4}
                value={y}
                onChange={handleYearChange}
                onBlur={handleYearBlur}
                onFocus={handleFocus}
                className="bg-transparent outline-none text-gray-700 font-medium text-center w-12 rounded focus:bg-blue-200 transition-colors p-0 placeholder-gray-400"
            />
        </div>
    );
};

const TimeSelect: React.FC<{ 
    value: string; 
    onChange: (val: string) => void; 
    inputRef?: React.RefObject<HTMLInputElement | null>;
    onComplete?: () => void;
}> = ({ value, onChange, inputRef, onComplete }) => {
    const [h = '00', m = '00'] = (value || '00:00').split(':');
    const minuteRef = useRef<HTMLInputElement>(null);
    const isFocused = useRef(false);

    // Sync state with props
    const [localH, setLocalH] = useState(h);
    const [localM, setLocalM] = useState(m);

    useEffect(() => {
        if (isFocused.current) return;
        const [newH = '00', newM = '00'] = (value || '00:00').split(':');
        setLocalH(newH);
        setLocalM(newM);
    }, [value]);

    const updateTime = (newH: string, newM: string) => {
        onChange(`${newH}:${newM}`);
    };

    const handleHourChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;

        if (val.length > 2) val = val.slice(-2);

        setLocalH(val);
        updateTime(val, localM);
        if (val.length === 2) minuteRef.current?.focus();
    };

    const handleHourBlur = () => {
        isFocused.current = false;
        let val = parseInt(localH, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(23, Math.max(0, val));
        const formatted = val.toString().padStart(2, '0');
        setLocalH(formatted);
        updateTime(formatted, localM);
    };

    const handleMinuteChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        let val = e.target.value;
        if (!/^\d*$/.test(val)) return;

        if (val.length > 2) val = val.slice(-2);

        setLocalM(val);
        updateTime(localH, val);
        if (val.length === 2 && onComplete) {
            onComplete();
        }
    };

    const handleMinuteBlur = () => {
        isFocused.current = false;
        let val = parseInt(localM, 10);
        if (isNaN(val)) val = 0;
        val = Math.min(59, Math.max(0, val));
        const formatted = val.toString().padStart(2, '0');
        setLocalM(formatted);
        updateTime(localH, formatted);
    };

    const handleFocus = (e: React.FocusEvent<HTMLInputElement>) => {
        isFocused.current = true;
        e.target.select();
    };

    return (
        <div className="flex items-center border border-gray-200 rounded-lg bg-gray-50 h-10 w-32 relative transition-all hover:border-gray-300 group">
             <div className="absolute inset-y-0 left-0 pl-2 flex items-center pointer-events-none text-gray-400 z-10">
                <Clock size={16} />
            </div>
            <div className="flex items-center pl-8 pr-2 w-full justify-between">
                <input 
                    ref={inputRef}
                    type="text"
                    value={localH} 
                    onChange={handleHourChange}
                    onBlur={handleHourBlur}
                    onFocus={handleFocus}
                    placeholder="HH"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
                <span className="text-gray-400 font-medium select-none">:</span>
                <input 
                    ref={minuteRef}
                    type="text"
                    value={localM} 
                    onChange={handleMinuteChange}
                    onBlur={handleMinuteBlur}
                    onFocus={handleFocus}
                    placeholder="MM"
                    className="bg-transparent outline-none text-gray-700 font-medium text-center w-9 rounded focus:bg-blue-200 transition-colors p-0"
                />
            </div>
        </div>
    );
};

export const EventModal: React.FC<EventModalProps> = ({ 
  isOpen, 
  onClose, 
  onSave, 
  onDelete,
  initialDate, 
  existingEvent 
}) => {
  const [title, setTitle] = useState('');

  // Separate date and time states
  const [startDate, setStartDate] = useState(''); // ISO YYYY-MM-DD
  const [startTime, setStartTime] = useState('');

  const [endDate, setEndDate] = useState(''); // ISO YYYY-MM-DD
  const [endTime, setEndTime] = useState('');

  const [description, setDescription] = useState('');
  const [location, setLocation] = useState('');
  const [color, setColor] = useState<EventColor>(EventColor.BLUE);
  const [isAllDay, setIsAllDay] = useState(false);

  // State to track which date picker is active
  const [activeDateField, setActiveDateField] = useState<'start' | 'end' | null>(null);
  const [calendarPos, setCalendarPos] = useState<'top' | 'bottom'>('bottom');

  // Refs for chaining focus
  const startDateRef = useRef<HTMLDivElement>(null);
  const endDateRef = useRef<HTMLDivElement>(null);

  const startHourRef = useRef<HTMLInputElement>(null);
  const endDayInputRef = useRef<HTMLInputElement>(null);
  const endHourRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isOpen) {
      if (existingEvent) {
        setTitle(existingEvent.title);
        const s = new Date(existingEvent.start);
        const e = new Date(existingEvent.end);

        setStartDate(toDateString(s));
        setStartTime(toTimeString(s));
        setEndDate(toDateString(e));
        setEndTime(toTimeString(e));

        setDescription(existingEvent.description || '');
        setLocation(existingEvent.location || '');
        setColor(existingEvent.color);
        setIsAllDay(existingEvent.isAllDay);
      } else {
        if (initialDate) {
             const s = new Date(initialDate);
             s.setHours(9, 0, 0, 0); 
             const e = new Date(s);
             e.setHours(10, 0, 0, 0); 

             setStartDate(toDateString(s));
             setStartTime(toTimeString(s));
             setEndDate(toDateString(e));
             setEndTime(toTimeString(e));
        } else {
             setStartDate('');
             setStartTime('');
             setEndDate('');
             setEndTime('');
        }

        setTitle('');
        setDescription('');
        setLocation('');
        setColor(EventColor.BLUE);
        setIsAllDay(false);
      }
      setActiveDateField(null);
    }
  }, [isOpen, existingEvent, initialDate]);

  // Handle clicking outside of active date field to close calendar
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
        if (activeDateField === 'start' && startDateRef.current && !startDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        } else if (activeDateField === 'end' && endDateRef.current && !endDateRef.current.contains(event.target as Node)) {
            setActiveDateField(null);
        }
    };

    if (activeDateField) {
        document.addEventListener('mousedown', handleClickOutside);
    }
    return () => {
        document.removeEventListener('mousedown', handleClickOutside);
    };
  }, [activeDateField]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    if (!startDate || !endDate) {
        return; 
    }

    const sTime = isAllDay ? '00:00' : (startTime || '00:00');
    const eTime = isAllDay ? '00:00' : (endTime || '00:00');

    const startIso = `${startDate}T${sTime}:00`;
    const endIso = `${endDate}T${eTime}:00`;

    onSave({
      id: existingEvent?.id || crypto.randomUUID(),
      title,
      start: startIso,
      end: endIso,
      description,
      location,
      color,
      isAllDay
    });
    onClose();
  };

  const handleDateSelect = (field: 'start' | 'end', newDate: Date) => {
    const dateStr = toDateString(newDate);

    if (field === 'start') {
        setStartDate(dateStr);
        if (!endDate || new Date(dateStr) > new Date(endDate)) {
            setEndDate(dateStr);
        }
    } else {
        setEndDate(dateStr);
    }
    setActiveDateField(null);
  };

  const openCalendar = (field: 'start' | 'end') => {
    const ref = field === 'start' ? startDateRef : endDateRef;
    if (ref.current) {
        const rect = ref.current.getBoundingClientRect();
        const spaceBelow = window.innerHeight - rect.bottom;
        if (spaceBelow < 320) {
            setCalendarPos('top');
        } else {
            setCalendarPos('bottom');
        }
    }
    setActiveDateField(field);
  };

  return (
    <Modal 
        isOpen={isOpen} 
        onClose={onClose} 
        title={existingEvent ? 'Edit Event' : 'New Event'}
    >
      <form onSubmit={handleSubmit} className="space-y-4 relative">

        {/* Title */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Event Title</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <Type size={16} />
                </div>
                <input
                    type="text"
                    required
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    placeholder="Add title"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                />
            </div>
        </div>

        {/* Date & Time Section */}
        <div className="grid grid-cols-1 gap-3">
             {/* Start Row */}
             <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Start</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={startDateRef}
                     >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                        <DateInput 
                            dateStr={startDate}
                            onChange={(iso) => {
                                setStartDate(iso);
                                // Smart logic: if end date < start date, sync it
                                if (!endDate || new Date(iso) > new Date(endDate)) {
                                    setEndDate(iso);
                                }
                            }}
                            onFocus={() => openCalendar('start')}
                            onComplete={() => {
                                if (isAllDay) {
                                    endDayInputRef.current?.focus();
                                } else {
                                    startHourRef.current?.focus();
                                }
                            }}
                        />
                         {activeDateField === 'start' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                 <MiniCalendar 
                                    initialDate={startDate ? new Date(startDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('start', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                     </div>

                     {/* Time Input (Custom) */}
                     {!isAllDay && (
                        <TimeSelect 
                            value={startTime} 
                            onChange={setStartTime} 
                            inputRef={startHourRef}
                            onComplete={() => endDayInputRef.current?.focus()}
                        />
                     )}
                </div>
            </div>

            {/* End Row */}
            <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">End</label>
                <div className="flex gap-2">
                     {/* Date Input */}
                     <div 
                        className="relative group flex-grow flex items-center bg-gray-50 border border-gray-200 rounded-lg h-10 pl-10 focus-within:ring-2 focus-within:ring-blue-500 transition-all hover:border-gray-300" 
                        ref={endDateRef}
                    >
                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400 z-10">
                            <CalendarIcon size={16} />
                        </div>
                         <DateInput 
                            dateStr={endDate}
                            onChange={setEndDate}
                            onFocus={() => openCalendar('end')}
                            inputRef={endDayInputRef}
                            onComplete={() => {
                                if (!isAllDay) {
                                    endHourRef.current?.focus();
                                }
                            }}
                        />
                        {activeDateField === 'end' && (
                            <div className={`absolute left-0 z-50 ${calendarPos === 'top' ? 'bottom-full mb-2' : 'top-full mt-2'}`}>
                                <MiniCalendar 
                                    initialDate={endDate ? new Date(endDate) : new Date()} 
                                    onSelectDate={(d) => handleDateSelect('end', d)} 
                                    onClose={() => setActiveDateField(null)} 
                                />
                            </div>
                        )}
                    </div>

                    {/* Time Input (Custom) */}
                    {!isAllDay && (
                         <TimeSelect 
                            value={endTime} 
                            onChange={setEndTime}
                            inputRef={endHourRef} 
                         />
                    )}
                </div>
            </div>
        </div>

        {/* All Day Toggle */}
        <div className="flex items-center gap-2">
            <input 
                type="checkbox" 
                id="isAllDay"
                checked={isAllDay}
                onChange={(e) => setIsAllDay(e.target.checked)}
                className="w-4 h-4 text-blue-600 border-gray-300 rounded focus:ring-blue-500 cursor-pointer"
            />
            <label htmlFor="isAllDay" className="text-sm text-gray-700 cursor-pointer select-none">All day event</label>
        </div>

        {/* Location */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Location</label>
            <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                    <MapPin size={16} />
                </div>
                <input
                    type="text"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    placeholder="Add location"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                />
            </div>
        </div>

        {/* Description */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Description</label>
            <div className="relative">
                 <div className="absolute top-3 left-3 flex items-start pointer-events-none text-gray-400">
                    <AlignLeft size={16} />
                </div>
                <textarea
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    placeholder="Add description"
                    className="w-full pl-10 pr-3 py-2 text-gray-700 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none resize-none h-20"
                />
            </div>
        </div>

        {/* Color Picker */}
        <div className="space-y-1">
            <label className="text-xs font-semibold text-gray-500 uppercase tracking-wider">Color</label>
            <div className="flex gap-2 flex-wrap">
                {Object.values(EventColor).map((c) => (
                    <button
                        key={c}
                        type="button"
                        onClick={() => setColor(c)}
                        className={`w-6 h-6 rounded-full transition-transform hover:scale-110 focus:outline-none focus:ring-2 focus:ring-offset-1 focus:ring-gray-300 ${color === c ? 'ring-2 ring-offset-1 ring-gray-400 scale-110' : ''}`}
                        style={{ backgroundColor: `var(--color-${c}-400, ${c})` }}
                    />
                ))}
            </div>
        </div>

        <div className="flex justify-between pt-4 border-t border-gray-100 mt-2">
            {existingEvent ? (
                 <button
                 type="button"
                 onClick={() => {
                     onDelete(existingEvent.id);
                     onClose();
                 }}
                 className="px-4 py-2 text-sm font-medium text-red-600 hover:bg-red-50 rounded-lg transition-colors"
             >
                 Delete
             </button>
            ) : <div></div>}

            <div className="flex gap-2">
                <button
                    type="button"
                    onClick={onClose}
                    className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                >
                    Cancel
                </button>
                <button
                    type="submit"
                    className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-lg hover:bg-blue-700 transition-colors shadow-sm"
                >
                    Save
                </button>
            </div>
        </div>
      </form>
    </Modal>
  );
};
